body:
For:
```mlir
hw.module @testStallability(%arg0: i32, %go: i1, %clk: i1, %rst: i1, %stall: i1) -> (out: i32) {
  %out, %done = pipeline.scheduled "MyPipeline"(%a0 : i32 = %arg0)
      stall(%s = %stall) clock(%c = %clk) reset(%r = %rst) go(%g = %go)
      {stallability = [true, false, true]} -> (out : i32) {
    pipeline.stage ^bb1 regs("a0" = %a0 : i32)
  ^bb1(%a0_0: i32, %s1_enable: i1):  // pred: ^bb0
    pipeline.stage ^bb2 regs("a0" = %a0_0 : i32)
  ^bb2(%a0_1: i32, %s2_enable: i1):  // pred: ^bb1
    pipeline.stage ^bb3 regs("a0" = %a0_1 : i32)
  ^bb3(%a0_2: i32, %s3_enable: i1):  // pred: ^bb2
    pipeline.return %a0_2 : i32
  }
  hw.output %out : i32
}
```

generates the following stallable (first) and non-stallable (second) stages:

```sv
module testStallability_MyPipeline_s0(
  input  [31:0] a0,
  input         enable,
                stall,
                clk,
                rst,
  output [31:0] a0_out,
  output        valid
);

  wire        _GEN = ~stall;
  reg  [31:0] a0_0;
  always_ff @(posedge clk) begin
    if (enable & _GEN)
      a0_0 <= a0;
  end
  reg         stage0_valid;
  always_ff @(posedge clk) begin
    if (rst)
      stage0_valid <= 1'h0;
    else begin
      if (_GEN)
        stage0_valid <= enable;
    end
  end
  assign a0_out = a0_0;
  assign valid = stage0_valid;
endmodule

module testStallability_MyPipeline_s1(
  input  [31:0] a0_in,
  input         enable,
                stall,
                clk,
                rst,
  output [31:0] a0_out,
  output        valid
);

  reg [31:0] a0;
  always_ff @(posedge clk)
    a0 <= a0_in;
  reg        stage1_valid;
  always_ff @(posedge clk) begin
    if (rst)
      stage1_valid <= 1'h0;
    else
      stage1_valid <= enable;
  end
  assign a0_out = a0;
  assign valid = stage1_valid;
endmodule
```
